import React, { useEffect, useState } from "react";
import { customStyles } from "../../../utils/tableCustomStyles";
import { tableTransactionConstant } from "./tableTransactionConstant";
import DataTable from "react-data-table-component";
import { getTransactionList } from "src/components/services/SubscriptionApi";

function PaymentRefundedList() {
    const [rowData, setRowData] = useState([]);

    useEffect(() => {
        fetchTransactionList();
    }, []);

    const fetchTransactionList = async () => {
        const response = await getTransactionList();
        if (response?.code === 200) {
            setRowData();
        }
    };

    return (
        <div className='row'>
            <div className="col2Large">
                <DataTable
                    title="Transaction"
                    columns={tableTransactionConstant(fetchTransactionList)}
                    data={rowData}
                    customStyles={customStyles}
                    pagination
                    paginationPerPage={10}
                    pointerOnHover
                    fixedHeader
                    noContextMenu
                    fixedHeaderScrollHeight={"calc(100vh - 226px)"}
                />
            </div>
        </div>
    );
}

export default PaymentRefundedList;
